// 🔧 Parser: Handles B2's empty type field & bilingual examples
function parseRawB2Data(rawArray) {
    const units = {};
    rawArray.forEach((line, index) => {
        if (!line || line.trim() === '') return;
        const parts = line.split('|');
        const u = parts[0] ? parts[0].trim() : '';
        let unitNum = parseInt(u);
        if (isNaN(unitNum)) return;


        let tType = parts[1] && parts[1].trim() !== '' ? parts[1].trim() : '';

        let rawDe = parts[2] ? parts[2].trim() : '';

        // WP-015: Grammar-based type inference for B2 words with empty type
        if (!tType) {
            const deTrimmed = rawDe.trim();
            const isCapitalized = /^[A-ZÄÖÜ]/.test(deTrimmed);
            // Matches article + anything, but we'll add a check so sentences starting with "Das " (like "Das war...") aren't counted as nouns unless they are short.
            const hasArticle = /^(der|die|das)\s/i.test(deTrimmed);
            const hasComma = deTrimmed.includes(',');
            const hasSpace = deTrimmed.includes(' ');

            // If it has an article (and isn't a long sentence starting with "Das"), or it's capitalized and is either a single word or has plural comma
            if ((hasArticle && !deTrimmed.includes('...')) || (isCapitalized && (!hasSpace || hasComma))) {
                tType = 'n'; // noun
            } else if (/\b(sich)\b/i.test(deTrimmed) || /^[a-zäöüß]+(en|ern|eln)(,|\s|\(|$)/.test(deTrimmed)) {
                tType = 'v'; // verb
            } else if (!hasSpace) {
                tType = 'a'; // adjective/adverb (single lowercase word)
            } else if (hasSpace) {
                tType = 'e'; // expression (multiple lowercase words, or sentences)
            } else {
                tType = 'Vocab';
            }
        }
        let deMain = rawDe;
        let deContext = "";

        const contextRegex = /\s*\(([^)]+\s+[^)]+)\)$/;
        const match = rawDe.match(contextRegex);

        if (match && !match[1].includes("Sg.") && !match[1].includes("Pl.") && !match[1].includes("D.") && !match[1].includes("G.") && !match[1].includes("A.")) {
            deContext = "(" + match[1] + ")";
            deMain = rawDe.replace(contextRegex, '').trim();
        }

        if (!units[unitNum]) units[unitNum] = [];
        units[unitNum].push({
            id: unitNum + '-' + units[unitNum].length, // WP-009: deterministic string ID
            de: deMain,
            deContext: deContext,
            en: parts[3] ? parts[3].trim() : '',
            type: tType,
            context: parts[4] ? parts[4].trim() : ''
        });
    });

    // Use actual max unit from data (will be 68). Do NOT pad to 70 — that creates
    // empty Modul 4 and Porträt slots in Chapter 10 that confuse the user.
    const maxUnit = Math.max(...Object.keys(units).map(Number));
    const result = [];
    for (let i = 1; i <= maxUnit; i++) {
        result.push(units[i] || []);
    }
    return result;
}

